using UnifiedToolkit.XWing;
namespace UnifiedToolkit.Conversion.Mapping.Upgrades;
public static class UpgradeMappingCoverageBuilder { public static IReadOnlyList<UpgradeMappingCoverageEntry> Build(IEnumerable<UpgradeDefinition> source,IEnumerable<UpgradeMapping> mappings,IEnumerable<UpgradeSourceAlternate> alternates,IEnumerable<UpgradeDisposition> dispositions){var m=mappings.ToDictionary(x=>x.SourceId,StringComparer.OrdinalIgnoreCase);var a=alternates.ToDictionary(x=>x.SourceId,StringComparer.OrdinalIgnoreCase);var d=dispositions.ToDictionary(x=>x.SourceId,StringComparer.OrdinalIgnoreCase);return source.OrderBy(x=>x.Name).ThenBy(x=>x.Id).Select(x=>{if(m.TryGetValue(x.Id,out var mm))return new UpgradeMappingCoverageEntry{SourceId=x.Id,SourceName=x.Name,SourceSlot=x.Slot,Status="ConvertedCanonical",CanonicalSourceId=x.Id,TargetId=mm.TargetId,TargetSlot=mm.Slot,Notes="Converted through a canonical First Edition upgrade mapping."};if(a.TryGetValue(x.Id,out var aa))return new UpgradeMappingCoverageEntry{SourceId=x.Id,SourceName=x.Name,SourceSlot=x.Slot,Status="AlternatePrinting",CanonicalSourceId=aa.CanonicalSourceId,TargetId=aa.TargetId,TargetSlot=aa.TargetSlot,Notes=aa.Notes};if(d.TryGetValue(x.Id,out var dd))return new UpgradeMappingCoverageEntry{SourceId=x.Id,SourceName=x.Name,SourceSlot=x.Slot,Status=dd.Kind.ToString(),Notes=dd.Reason};return new UpgradeMappingCoverageEntry{SourceId=x.Id,SourceName=x.Name,SourceSlot=x.Slot,Status="Unmapped",Notes="No mapping, alternate relationship, or disposition exists."};}).ToList();}}
